SELECT

FROM
    dm_auth_user
WHERE
    parent_id = #{parentId}
and
    bind_account = #{bindAccount}
and
    bind_type = #{bindType,javaType=com.clougence.clouddm.platform.dal.model.auth.AccountBindType}

SELECT

FROM
    dm_auth_user
WHERE
    parent_id = #{parentId}

        AND role_id=#{roleId}


        AND (
            (username LIKE CONCAT(#{prefix},'%') OR account LIKE
            CONCAT(#{prefix},'%')) OR uid = #{prefix}
        )

order by gmt_create desc

SELECT

FROM
    dm_auth_user
WHERE
    phone = #{phone}
AND username = #{username}
AND email = #{email}
AND account_type = 'PRIMARY_ACCOUNT'

